from zeep import Client
from zeep.helpers import serialize_object
from zeep.exceptions import Fault
from lxml import etree
import re

def sanitize_input(user_input):
    return re.sub(r'[^\w\s]', '', user_input)

def create_soap_client(wsdl_url):
    return Client(wsdl=wsdl_url)

def lookup_policy(client, policy_number, customer_name):
    sanitized_policy_number = sanitize_input(policy_number)
    sanitized_customer_name = sanitize_input(customer_name)
    
    try:
        response = client.service.PolicyLookup(
            PolicyNumber=sanitized_policy_number,
            CustomerName=sanitized_customer_name
        )
        return serialize_object(response)
    except Fault as fault:
        return f"An error occurred: {fault}"

def main():
    wsdl_url = 'http://example.com/insurance?wsdl'
    client = create_soap_client(wsdl_url)
    
    policy_number = input("Enter Policy Number: ")
    customer_name = input("Enter Customer Name: ")
    
    result = lookup_policy(client, policy_number, customer_name)
    print(result)

if __name__ == "__main__":
    main()